áp dụng đoạn code dưới dây vào những phần chưa có trong module kocreview:


/**
 * Phân tích và "tách" trang phục ra khỏi người mẫu trong ảnh gốc bằng text mô tả chi tiết.
 * Được tinh chỉnh để hoàn toàn bỏ qua nhân dạng người mẫu.
 */
export const describeKocOutfit = async (outfitPart: any): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Analyze the CLOTHING in this image in extreme detail for an AI image generator.

    !!! CRITICAL PRIVACY & IDENTITY RULE !!!: 
    - Focus ONLY on the garments, fabric, shoes, and accessories. 
    - COMPLETELY IGNORE the person's face, ethnicity, hair, and identity. 
    - Do not mention any physical traits of the person, only the clothes.

    Describe in detail:
    1. Type of garments (e.g., oversized blazer, cropped hoodie).
    2. Fabric and Texture (e.g., heavy denim, silk, ribbed knit).
    3. Exact Colors and Patterns.
    4. Fit and Layering.

    Return a concise but highly descriptive technical fashion paragraph in English.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, { inlineData: outfitPart }] }
    });
    return response.text?.trim() || "A stylish outfit.";
  } catch (error) {
    console.error("Outfit description error", error);
    return "Detailed fashion outfit.";
  }
};

/**
 * Generates TikTok script parts for a given product and scene count.
 */
export const generateKocScript = async (
  imageParts: any[], productName: string, keyword: string, scriptTone: string,
  productSize: string, scriptNote: string, scriptLayout: string, gender: string, voice: string,
  sceneCount: number
): Promise<ScriptParts> => {
  const ai = getAiClient();

  let dialectInstruction = "";
  if (voice === 'Miền Bắc') {
    dialectInstruction = `
      VĂN PHONG MIỀN BẮC (HÀ NỘI):
      - Sử dụng từ đệm: "nhé", "ạ", "thế", "đấy", "vậy", "vâng", "chứ".
      - Cách dùng từ: "không", "vẫn", "thế này".
      - TUYỆT ĐỐI KHÔNG dùng các từ miền Nam như: nha, nè, nghen, thiệt, hông, vầy, bển, trển, hết sảy, xịn sò (kiểu Nam).
    `;
  } else {
    dialectInstruction = `
      VĂN PHONG MIỀN NAM (SÀI GÒN):
      - Sử dụng từ đệm: "nha", "nè", "nghen", "hen", "đó", "vầy", "nghen", "ha".
      - Cách dùng từ: "hông" (thay cho không), "thiệt" (thay cho thật), "dễ thương dữ thần", "hết sảy".
      - TUYỆT ĐỐI KHÔNG dùng các từ miền Bắc như: nhé, ạ, thế, đấy, chả, vâng, thế này.
    `;
  }

  const prompt = `
    Tạo kịch bản TikTok viral cho "${productName}". 
    USP: "${keyword}". 
    Kích thước: "${productSize}". 
    Bố quát tổng quát: "${scriptLayout}". 
    Xưng hô: "em", gọi "anh chị". 
    Giới tính: ${gender}.

    YÊU CẦU ĐẶC BIỆT VỀ NỘI DUNG:
    - Kịch bản phải có đúng CHÍNH XÁC ${sceneCount} phần (tương ứng v1, v2, ..., v${sceneCount}).
    - TUYỆT ĐỐI KHÔNG nhắc đến bối cảnh, địa điểm, không gian hay môi trường xung quanh trong lời thoại (Ví dụ: Không nói "Em đang ở quán cafe", "Hôm nay đứng ở phòng khách", "Chào cả nhà từ sân vườn"...). 
    - Nội dung chỉ tập trung vào sản phẩm, trải nghiệm sử dụng và cảm xúc cá nhân.

    ${dialectInstruction}

    YÊU CẦU CHUNG: 
    - Tuyệt đối không dùng từ cấm: Shopee, Lazada, Tiki, TikTok Shop. 
    - Mỗi phần (v1, v2, ...) dưới 190 ký tự. 
    - Ngữ điệu ${scriptTone || "tự nhiên, hào hứng, kịch tính, tạo cảm giác FOMO"}.
  `;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
    const key = `v${i}`;
    properties[key] = { type: Type.STRING };
    required.push(key);
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties,
          required
        }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (e) {
    console.error("Generate script error", e);
    const fallback: ScriptParts = {};
    for (let i = 1; i <= sceneCount; i++) fallback[`v${i}`] = '';
    return fallback;
  }
};

/**
 * Generates an image based on character, outfit, and product references.
 * Reinforces absolute face isolation from outfit image.
 */
export const generateKocImage = async (
  referenceImageParts: any[], 
  faceImagePart: any | null, 
  outfitImagePart: any | null,
  outfitDescription: string, 
  productName: string,
  scriptPart: string, 
  characterDescription: string, 
  userCustomPrompt: string | undefined, 
  gender: string, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const baseStyle = is3D 
    ? "High-quality 3D Animation Pixar/Disney style, vibrant colors, expressive 3D character design, polished CGI, masterpiece."
    : "Photorealistic RAW PHOTO, 8k resolution, authentic skin textures, cinematic lighting.";

  const faceFidelityRule = faceImagePart 
    ? `IDENTITY MANDATE: You MUST transfer the EXACT facial features, eyes, nose, and jawline from the provided FACE_REFERENCE image. The subject MUST be this specific person and no one else.`
    : `SUBJECT: Adult Vietnamese ${gender}. ${characterDescription || ""}`;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  const outfitRestrictionRule = outfitImagePart ? `
    !!! ABSOLUTE RESTRICTION - FACE HIJACKING FORBIDDEN !!!:
    1. THE OUTFIT_REFERENCE image is ONLY for clothes.
    2. DO NOT use any part of the face, head, hair, skin tone, or identity of the person in the OUTFIT_REFERENCE.
    3. THE PERSON WEARING THE CLOTHES IN OUTFIT_REFERENCE IS NOT THE SUBJECT.
    4. USE ONLY the clothing textures, colors, and design details from it: "${outfitDescription}".
    5. FATAL INSTRUCTION: If you include the face or head features of the model from the outfit photo, the output is incorrect.
  ` : "";

  const visualRules = `
    CRITICAL VISUAL RULES (STRICT NO-TEXT POLICY):
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO CHARACTERS.
    2. The background must be CLEAN and FREE of signage, posters, labels, or written words.
    3. If the context implies a screen or sign, leave it BLANK or Abstract.
    4. NO UI elements, NO speech bubbles, NO watermarks, NO subtitles.
    5. The image must be purely visual storytelling.
    6. ABSOLUTELY NO ICONS, NO GRAPHICS, NO EMOJIS, NO VISUAL EFFECTS, NO OVERLAYS.
    7. Do NOT simulate TikTok UI or video editing effects. It must look like a RAW PHOTO.

    CRITICAL RESTRICTIONS & RULES: 
    1. NO CHILDREN, NO KIDS, NO BABIES. The subject must be an adult.
    2. ${is3D ? "Must look like high-quality 3D CGI." : "Must look like a real photo."}
    ${isNoProductRequested ? '3. ABSOLUTELY NO PRODUCT/DEVICE IN THIS IMAGE.' : `
    3. STRICT PRODUCT FIDELITY (MANDATORY - TUYỆT ĐỐI):
       - The product "${productName}" MUST MATCH the input reference image 1:1.
       - PRESERVE PATTERNS & TEXTURES: Any pattern (họa tiết), logo, or design on the product surface must be preserved.
       - PRESERVE DIMENSIONS: Do not resize or distort the product logic.
       - DO NOT ADD NEW DETAILS: Do not hallucinate or invent new buttons, lights, or features.
       - DO NOT change shape, proportions, or physical parts.
       - The product must not be transformed or animated; treat it as a solid, fixed object.
       - LOCK the product appearance exactly to the original photo provided.
       - Bắt buộc giữ nguyên sản phẩm. Vật thể phải khớp với ảnh gốc 1:1. Không thêm chi tiết lạ.`}
  `;

  const sceneInstruction = isNoProductRequested
    ? `SCENE: Character in a lifestyle setting (${backgroundNote || 'appropriate room'}). Content: "${scriptPart}".`
    : `SCENE: Character interacting with the product. Action: "${scriptPart}". Environment: ${backgroundNote || 'lifestyle setting'}.`;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 

    ${faceFidelityRule}
    ${outfitRestrictionRule}
    ${visualRules}
    ${sceneInstruction} 

    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (!isNoProductRequested && referenceImageParts.length > 0) contents.push({ inlineData: referenceImageParts[0] });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

/**
 * Generates a video prompt for VEO-3 model based on script and visual context.
 */
export const generateKocVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceTag = voice === 'Miền Bắc' ? 'Northern Vietnamese' : 'Southern Vietnamese';
  const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

  const productInteractionRule = isNoProductRequested
    ? `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - TUYỆT ĐỐI KHÔNG xuất hiện sản phẩm "${productName}".
      - Nhân vật đứng trước ống kính, tươi cười rạng rỡ, biểu cảm khuôn mặt.`
    : `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - Nhân vật đang cầm trên tay sản phẩm "${productName}".
      - Hành động: Nhân vật đứng trước ống kính, tươi cười rạng rỡ, khoe sản phẩm.
      - [SẢN PHẨM PHẢI GIỐNG ẢNH THAM CHIẾU 100%, KHÔNG BIẾN DẠNG]`;

  const instructionPrompt = `
  Nhiệm vụ: Viết một lời nhắc (Prompt) chi tiết để tạo video AI (VEO-3) dài 8 giây cho video KOC Review.
  PHONG CÁCH VIDEO: ${is3D ? "3D Animation / CGI Style" : "Photorealistic / Real Life Style"}.

  CẤU TRÚC PROMPT:
  PHẦN 1: NHÂN VẬT & DIỆN MẠO (BẮT BUỘC NHẤT QUÁN). Nhân vật người Việt Nam. ${is3D ? "Phong cách hoạt hình 3D Pixar/Disney." : "Phong cách người thật chân thực."}
  ${productInteractionRule}
  PHẦN 3: BỐI CẢNH & ÁNH SÁNG. Một không gian sống hiện đại, sạch sẽ. ${is3D ? "Môi trường 3D sống động." : "Ánh sáng điện ảnh chân thực."}
  PHẦN 4: CHUYỂN ĐỘNG MÁY ẢNH (9:16).
  PHẦN 5: LỜI THOẠI (DÙNG CHO ĐỒNG BỘ): ✨ Model speaks in ${voiceTag} voice (${voiceGender}): "${scriptText}"
  PHẦN 6: CHẤT LƯỢNG KỸ THUẬT: 4K, ${is3D ? "3D Animation, Masterpiece CGI, 60fps" : "Realistic, Cinematic Lighting, Photorealistic, 60fps"}.

  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất (trừ phần lời thoại). Không xuống dòng.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  if (generatedImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: contents }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    return "Error generating video prompt.";
  }
};

