                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                      Tải File Prompt (.txt)
                    </button>
                  </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

export default KocReviewModule;

import { GoogleGenAI, Type } from "@google/genai";
import { ScriptParts, ScriptPartKey } from "../types";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Phân tích và "tách" trang phục ra khỏi người mẫu trong ảnh gốc bằng text mô tả chi tiết.
 */
export const describeKocOutfit = async (outfitPart: any): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Analyze the CLOTHING in this image in extreme detail for an AI image generator.

    !!! CRITICAL PRIVACY & IDENTITY RULE !!!: 
    - Focus ONLY on the garments, fabric, shoes, and accessories. 
    - COMPLETELY IGNORE the person's face, ethnicity, hair, and identity. 

    Describe in detail: garments, fabric, textures, colors, patterns, and fit.
    Return a concise technical fashion paragraph in English.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, { inlineData: outfitPart }] }
    });
    return response.text?.trim() || "A stylish outfit.";
  } catch (error) {
    console.error("Outfit description error", error);
    return "Detailed fashion outfit.";
  }
};

/**
 * Generates TikTok script parts.
 */
export const generateKocScript = async (
  imageParts: any[], productName: string, keyword: string, scriptTone: string,
  productSize: string, scriptNote: string, scriptLayout: string, gender: string, voice: string,
  sceneCount: number
): Promise<ScriptParts> => {
  const ai = getAiClient();

  let dialectInstruction = "";
  if (voice === 'Miền Bắc') {
    dialectInstruction = `VĂN PHONG MIỀN BẮC (HÀ NỘI): nhé, ạ, thế, đấy, chứ. KHÔNG dùng từ miền Nam.`;
  } else {
    dialectInstruction = `VĂN PHONG MIỀN NAM (SÀI GÒN): nha, nè, nghen, thiệt, hông, vầy. KHÔNG dùng từ miền Bắc.`;
  }

  const prompt = `
    Tạo kịch bản TikTok cho "${productName}". USP: "${keyword}". Layout: "${scriptLayout}". Xưng hô: "em", gọi "anh chị". Giới tính: ${gender}.
    YÊU CẦU: Đúng ${sceneCount} phần (v1..v${sceneCount}). KHÔNG nhắc bối cảnh/địa điểm. Chỉ tập trung sản phẩm và cảm xúc.
    ${dialectInstruction}
    Dưới 190 ký tự/phần. Ngữ điệu: ${scriptTone || "tự nhiên"}.
  `;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
