/**
 * Generates an image based on character, outfit, and product references.
 * Now strictly enforces characterDescription for body type, style, and clothing.
 */
export const generateKocImage = async (
  referenceImageParts: any[], 
  faceImagePart: any | null, 
  outfitImagePart: any | null,
  outfitDescription: string, 
  productName: string,
  scriptPart: string, 
  characterDescription: string, 
  userCustomPrompt: string | undefined, 
  gender: string, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = "",
  visualNote: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const baseStyle = is3D 
    ? "High-quality 3D Animation Pixar/Disney style, vibrant colors, expressive character design, polished CGI, masterpiece."
    : "Photorealistic RAW PHOTO, 8k resolution, authentic skin textures, cinematic lighting.";

  // Ưu tiên tuyệt đối các ghi chú về nhân vật (vóc dáng, phong cách, quần áo)
  const characterFidelityRule = `
    !!! CRITICAL CHARACTER FIDELITY MANDATE (ABSOLUTE PRIORITY) !!!:
    You MUST strictly follow these instructions for the character's physical appearance and style:
    - DESCRIPTION: "${characterDescription}"
    - GENDER: Adult Vietnamese ${gender}.
    - MANDATORY: If the description mentions a specific body type (e.g., chubby, muscular, slim), clothing style, or fashion vibe, you MUST apply it 100%. 
    - This text-based character description OVERRIDES any default assumptions or model traits from reference images.
  `;

  const identityRule = faceImagePart 
    ? `IDENTITY: Transfer the EXACT facial features and bone structure from the provided FACE_REFERENCE image. However, the body shape and clothing MUST follow the "CHARACTER FIDELITY MANDATE" above.`
    : `IDENTITY: A young adult Vietnamese ${gender} whose appearance is defined by the mandate above.`;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  const outfitRule = outfitImagePart ? `
    OUTFIT REFERENCE: Use details from "${outfitDescription}". 
    CRITICAL: If the "CHARACTER FIDELITY MANDATE" above specifies different clothes or a specific style, PRIORITIZE the description over the outfit image. 
    NEVER use the face of the person in the outfit reference image.
  ` : "";

  const visualRules = `
    STRICT NO-TEXT POLICY: NO letters, NO UI, NO symbols.
    RESTRICTIONS: NO children, NO babies. Subject must be an adult.
    ${!isNoProductRequested ? `PRODUCT FIDELITY: The product "${productName}" MUST match the reference image 1:1. No distortions.` : 'NO PRODUCT in this image.'}
  `;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 

    ${characterFidelityRule}
    ${identityRule}
    ${outfitRule}
    ${visualRules}
    ${visualNote ? `COMPOSITION: ${visualNote}.` : ""}
    SCENE: Character in ${backgroundNote || 'a lifestyle setting'}. Action/Context: "${scriptPart}".

    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (!isNoProductRequested && referenceImageParts.length > 0) contents.push({ inlineData: referenceImageParts[0] });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

